  ('generalpolice-f3743df6-moex-00106', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-113-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '有關立法委員之文件調閱權，下列敘述何者錯誤？', '["立法院得向檢察機關調閱已偵查終結而不起訴處分確定之案件卷證", "文件調閱權之行使，係經院會或委員會之決議行之", "國家機關獨立行使職權受憲法保障者，文件調閱權之行使即應受限制", "考試機關對於應考成績之評定，無涉機關獨立行使職權，得經院會決議調閱文件原本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:43+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "306", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00107', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-113-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '關於考試院，下列敘述何者錯誤？', '["考試院為合議制機關", "考試院院長並為考試委員及考試院會議主席", "考試委員由總統提名，經立法院同意後任命", "考試院就所掌事項得向立法院提出法律案"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:43+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "306", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00108', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-113-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '依憲法訴訟法規定，下列何種憲法法庭判決，必須經過言詞辯論才能作成？', '["總統彈劾案", "統一解釋法律案件", "機關爭議案件", "地方自治保障案件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:43+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "306", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00109', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-113-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '下列何種情形，限制人身自由之行政機關毋須於24小時內移送法院審理？', '["衛生主管機關認疑似被傳染者有強制隔離之必要時", "人民因犯罪嫌疑被逮捕拘禁，檢察官經訊問後認有羈押之必要時", "受收容之外國人於暫時收容期間內，對於暫時收容處分表示不服時", "行政執行官拘提義務人並經詢問後，認有對義務人為管收處分之必要時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:43+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "306", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00110', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-113-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '有關訴訟權，下列敘述何者錯誤？', '["基於「有權利必有救濟」原則，人民權利受有侵害，均得向法院尋求救濟", "立法機關對於受理爭議的裁判機關及審級，有一定之裁量權，但仍應受司法審查", "特別類型案件如設置有特別程序，違反訴訟平等原則", "法院不得以法律有漏洞而拒絕審判"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:43+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "306", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00111', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-113-3d2b73b6', 'sub-generalpolice-f3743df6-05', NULL, 'single_choice', '憲法第19條規定，人民有依法律納稅之義務。依司法院大法官解釋，下列敘述何者錯誤？', '["國家課人民以繳納稅捐之義務時，應以法律明定租稅主體等租稅構成要件", "累進稅率使所得較高者必須負擔高額賦稅，故違反平等原則之要求", "國家提供人民稅捐減免優惠時，亦有租稅法定主義之適用", "稅捐稽徵機關絕對不得逾越法律解釋之範圍，而增加法律所無之租稅義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:43+00:00", "source_pdf_sha1": "f0c6a23ff7fb", "answer_pdf_sha1": "a74147423676", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "306", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL)
